// Prebuilt minified bundle (UMD-like) for direct inclusion as theme asset
(function(window){
  // Minimal bundled code: fetchPlans, widget rendering, and init
  function fetchPlans(productId, apiUrl){
    var demo=[{id:'w1',name:'1 Year Protection',price:'9.99',price_display:'$9.99',term:'1 year'},{id:'w2',name:'2 Year Protection',price:'16.99',price_display:'$16.99',term:'2 years'}];
    if(!apiUrl){return new Promise(function(r){setTimeout(function(){r(demo);},250);});}
    var url=new URL(apiUrl,location.origin);
    if(productId)url.searchParams.set('product_id',productId);
    return fetch(url.toString()).then(function(res){if(!res.ok)throw new Error('Failed');return res.json();}).then(function(d){return d.plans||d;});
  }
  function escapeHtml(s){if(!s)return'';return String(s).replace(/[&<>\"']/g,function(c){return{'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c];});}
  function render(mountEl,plans,onPlanSelected){
    var root=document.createElement('div');root.className='warranty-widget-root';root.innerHTML='<div class="warranty-header">Warranty</div><div class="warranty-body"></div>';
    mountEl.appendChild(root);
    var container=root.querySelector('.warranty-body');
    if(!plans||plans.length===0){container.innerHTML='<div class="warranty-none">No warranty available for this product.</div>';return}
    var list=document.createElement('div');list.className='warranty-list';plans.forEach(function(plan){var item=document.createElement('button');item.type='button';item.className='warranty-item';item.setAttribute('aria-pressed','false');item.innerHTML='<div class="warranty-name">'+escapeHtml(plan.name)+'</div><div class="warranty-price">'+escapeHtml(plan.price_display||plan.price)+'</div><div class="warranty-term">'+escapeHtml(plan.term||'')+'</div>';item.addEventListener('click',function(){Array.prototype.forEach.call(document.querySelectorAll('.warranty-item'),function(i){i.setAttribute('aria-pressed','false')});item.setAttribute('aria-pressed','true');onPlanSelected(plan);});list.appendChild(item);});container.innerHTML='';container.appendChild(list);
  }
  function defaultOnSelect(plan){var form=document.querySelector('form[action*="/cart/add"], form[action*="cart/add"], form#add_to_cart, form.product-form');if(form){var prev=form.querySelector('input[name="properties[Warranty]"]');if(prev)prev.remove();var input=document.createElement('input');input.type='hidden';input.name='properties[Warranty]';input.value=plan.name+' — '+(plan.price_display||plan.price||'');form.appendChild(input);var note=document.querySelector('.warranty-selected-note');if(note)note.textContent='Selected warranty: '+plan.name;else{var el=document.createElement('div');el.className='warranty-selected-note';el.textContent='Selected warranty: '+plan.name;form.parentNode.insertBefore(el,form.nextSibling);} }else{console.warn('WarrantyWidget: No add-to-cart form found');}}
  function init(options){options=options||{};var selector=options.mountSelector||options.mount||'#warranty-widget';var mountEl=options.mountElement||document.querySelector(selector);if(!mountEl){console.warn('WarrantyWidget mount not found',selector);return}fetchPlans(options.productId,options.apiUrl).then(function(plans){render(mountEl,plans,options.onPlanSelected||defaultOnSelect);}).catch(function(err){var container=mountEl.querySelector('.warranty-body');if(container)container.innerHTML='<div class="warranty-error">Unable to load warranty plans.</div>';console.error(err);});}
  window.WarrantyWidget=window.WarrantyWidget||{};window.WarrantyWidget.init=init;document.addEventListener('DOMContentLoaded',function(){var mounts=document.querySelectorAll('[data-warranty-mount], #warranty-widget');Array.prototype.forEach.call(mounts,function(el){var api=el.getAttribute('data-warranty-api');var productId=el.getAttribute('data-product-id')||el.dataset.productId;var mount=el.getAttribute('data-warranty-mount')||('#'+el.id);window.WarrantyWidget.init({mountSelector:mount,apiUrl:api,productId:productId,mountElement:el});});});
})(window);
